A generic implementation that mutably sorts the input array by recursively pivoting around a specific point that is randomly selected pub trait QuickSort { fn quick_sort(&mut self);
} impl<T> QuickSort for [T] where T: Copy + Clone + Ord { /// Sorts a given array using the Quick Sort algorithm. /// The function rearranges the array contents rather than returning a new sorted copy of the input array /// ``` /// use csx3::sort::quick::QuickSort; /// /// let v = &mut [3,5,8,1,2,4,6,0]; /// /// v.quick_sort(); /// assert_eq!(v, &[0,1,2,3,4,5,6,8]); /// ``` fn quick_sort(&mut self) { // have we reached the end of the recursion ? if self.len() < 2 { return; } // pick an index at random based on a uniform distribution let idx = self.len() >> 1; // partition the array into to mutable slices for further sorting let (left_partition,_ , right_partition) = self.partition_at_idx(idx); // Recurse against left an right partitions left_partition.quick_sort(); right_partition.quick_sort(); }
}

