Hence, by putting all the above together, we have the following implementation for the CountSort trait /// Sorts a given array using the Count Sort algorithm.
/// Input array NuType shouldn't exceed u16 to avoid memory issues
/// ```
/// use csx3::sort::count::CountSort;
///
/// let v = &mut [3i8,5,8,1,2,4,6,0];
///
/// v.count_sort();
/// assert_eq!(v, &[0,1,2,3,4,5,6,8]);
/// ```
pub trait CountSort { fn count_sort(&mut self);
} // CountSort macro implementation for singed and unsigned types
impl<T> CountSort for [T] where T: Distance<T> + Copy + Ord + Debug{ fn count_sort(&mut self) { if self.len() < 2 { return; } // find min and max elements // so we can construct the boundaries of the counting array // i.e. if (min,max) = (13232, 13233) then we need only an array with capacity(2) let (min, max) = min_max(self); // construct a counting array with length = Max - Min + 1 let len: usize = max.dist_from(min); // initialise it with zero counts let mut count = vec![0usize; len + 1]; // and finally measure counts per item self.iter() .for_each(|x| { // construct index offset based on Min value, such as, Min is at [0] position let idx: usize = x.dist_from(min); count[idx] += 1; }); // play back onto the input slice the counts collected with Sum of all counts == slice.len() let iter = &mut self.iter_mut(); count.into_iter() .enumerate() .filter(|(_, x)| *x > 0) .for_each(|(i, x)| { // place value at `x` positions iter.take(x) // translate index -> value // given value = Min + index .for_each(|n| { *n = min.add_index(i ) }); }); }
}
/// Distance calculation between two types that are either both signed or unsigned
/// Returns the distance as unsigned type
pub trait Distance<T> { fn dist_from(&self, min: T) -> usize; fn add_index(&self, idx: usize) -> T;
} /// Macro implementation of Distance trait for all signed types
macro_rules! impl_dist_signed { ( $($x:ty),*) => { $( impl Distance<$x> for $x { #[inline] fn dist_from(&self, min: $x) -> usize { if *self > min { (*self as usize).wrapping_sub(min as usize) } else { (min as usize).wrapping_sub(*self as usize) } } #[inline] fn add_index(&self, idx: usize) -> $x { self.wrapping_add(idx as $x) } } )* }
}
impl_dist_signed!(i8,i16,i32,isize,u8,u16,u32,usize);

