Where pivot selected is chosen randomly based on the 75/25 rule pub trait Select<T> { fn r_selection(&mut self, nth_min: usize) -> &T;
} impl<T> Select<T> for [T] where T: Copy + Ord { /// Find the nth order statistic within an unordered set with O(n) performance /// using nth_min as 1 will return the smallest item; 2 the second smallest, etc /// When function returns, the input array has been rearranged so that ```item == array[ nth order ]``` /// ``` /// use csx3::select::Select; /// /// let (arr, nth_order) = (&mut [23,43,8,22,15,11], 1usize); /// /// let ret_val = arr.r_selection(nth_order); /// assert_eq!(ret_val, &8); /// assert_eq!(&arr[nth_order-1], &8); /// ``` fn r_selection(&mut self, nth_min: usize) -> &T { // println!("Input: {:?}::{}th", v, order_nth); if self.len() == 1 { return &self[0]; } // pick an index at random based on a uniform distribution let idx = rand::thread_rng().gen_range(0..(self.len() - 1)); // find out the nth order of this sample let (left_partition, nth, right_partition) = self.partition_at_idx(idx); let order = left_partition.len() + 1; // println!("\tAsked:{}ord Picked:{}th, {:?} {:?}ord {:?}", nth_min, idx, left_partition, order, right_partition); // is nth order sampled over, equal or above the desired nth_min ? match nth_min.cmp(&order) { // we've found the item in nth_min order Ordering::Equal => nth, // the nth_min is below the nth found so recurse on the left partition Ordering::Less => left_partition.r_selection(nth_min), // the nth_min is above the nth found so recurse on the right partition with adjusted order Ordering::Greater => right_partition.r_selection(nth_min - order), } }
}

