Where the pivot selected is always the median of the recursive set provided by the below implementation The idea is to break the array into chunks of 5 elements sort them and pick chunk[3] as the median Collect all medians into a new array recurse until you converge to the median /// Returns a vector of N/5 medians where N = input array length
/// It breaks array into N/5 sub-arrays of length 5 for cheap sorting and picking the median value
///
pub fn medians_of_medians<T>(v:&mut [T]) -> Vec<T> where T : Copy + Ord + Debug { // extract median of medians array // split input slice into n/5 groups of 5 v.chunks_mut(5) .map(|chunk| { // sort each group chunk.mergesort_mut(Merge::merge_mut_adjacent); // pull the median out chunk[ chunk.len() >> 1] }) // return as vector .collect()
} /// Finds the median value within an array of N elements
pub fn find_median<T>(v:&mut [T]) -> T where T : Copy + Ord + Debug { if v.len() == 1 { return v[0] } let mut medians: Vec<T> = medians_of_medians(v); find_median(&mut medians)
}
